#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=155;
const double inf=1e9;
int n,mxnum[N],f[N];
double dis[N][N],mx[N],ans,x[N],y[N],dis2[N];
void fun(double num)
{
	int tmp=num;
	cout<<tmp<<".";
	num-=tmp;
	for(int i=1;i<=6;i++)
	{
		int t=num*10;
		cout<<t;
	}
}
int find(int x)
{
    if(f[x]==x) return x;
    return f[x]=find(f[x]);
}
int main()
{
//	ios::sync_with_stdio(0);
//	cin.tie(0),cout.tie(0);
	cin>>n;
//	fun(inf);
	ans=inf;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i]>>y[i];
        f[i]=i;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			dis[i][j]=inf;
		}
	}
	for(int i=1;i<=n;i++)
	{
		dis[i][i]=0;
		string s;
		cin>>s;
		s=" "+s;
		for(int j=1;j<i;j++)
		{
			if(s[j]=='1')
			{
				int tmp2=abs(x[i]-x[j])*abs(x[i]-x[j])+abs(y[i]-y[j])*abs(y[i]-y[j]);
//				cout<<i<<" "<<j<<" "<<tmp2<<" ";
				double tmp=sqrt(tmp2);
				dis[i][j]=dis[j][i]=tmp;
//				fun(tmp);
//				cout<<tmp;
//				cout<<"\n";
                if(find(i)!=find(j))
                {
                    f[find(i)]=find(j);
                }
			}
//			fun(dis[i][j]);
//			cout<<"  ";
		}
//		cout<<"\n";
	}
	for(int k=1;k<=n;k++)
	{
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++)
			{
				dis[i][j]=min(dis[i][j],dis[i][k]+dis[k][j]);
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			if(dis[i][j]!=inf)
			{
				if(mx[i]<dis[i][j])
				{
					mx[i]=dis[i][j];
					mxnum[i]=j;
				}

			}
		}
        dis2[find(i)]=max(dis2[find(i)],mx[i]);
//		cout<<mx[i]<<' '<<mxnum[i]<<"\n";
	}
//	cout<<"\n";
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			if(i==j) continue;
			if(dis[i][j]!=inf) continue;
			double tmp=sqrt(abs(x[i]-x[j])*abs(x[i]-x[j])+abs(y[i]-y[j])*abs(y[i]-y[j]));
//			cout<<i<<' '<<j<<" "<<tmp<<" "<<tmp+mx[i]+mx[j]<<" "<<max(tmp+mx[i]+mx[j],max(mx[mxnum[i]],mx[mxnum[i]]))<<"\n";
			ans=min(ans,max(tmp+mx[i]+mx[j],max(dis2[find(i)],dis2[find(j)])));
		}
	}
	printf("%.6lf",ans);
//	int tmp=ans;
//	cout<<tmp<<".";
//	ans-=tmp;
//	for(int i=1;i<=6;i++) 
//	{
//		int t=ans*10;
//		cout<<t;
//	}
//	cout<<ans;
	return 0;
}
